	if p.isScrolling && p.viewport.Height > 0 && len(p.viewport.View()) == 0 {
		content, err := instance.PreviewFullHistory()
		if err != nil {
			return err
		}
		footer := lipgloss.NewStyle().Foreground(ColorMuted).Render("ESC to exit scroll mode")
